static const char *modbus_fc_to_str(uint8_t fc)
{
    switch (fc) {
    case 0x01: return "Read Coils";
    case 0x02: return "Read Discrete Inputs";
    case 0x03: return "Read Holding Registers";
    case 0x04: return "Read Input Registers";
    case 0x05: return "Write Single Coil";
    case 0x06: return "Write Single Register";
    case 0x0F: return "Write Multiple Coils";
    case 0x10: return "Write Multiple Registers";
    default:   return "Unknown";
    }
}

static void modbus_gw_send_resp(int client_sock, const struct modbus_adu *resp)
{
    uint8_t frame[MODBUS_MBAP_AND_FC_LENGTH + sizeof(resp->data)];
    size_t frame_len = MODBUS_MBAP_AND_FC_LENGTH + resp->length;

    modbus_raw_put_header(resp, frame);
    memcpy(frame + MODBUS_MBAP_AND_FC_LENGTH, resp->data, resp->length);

    int sent = sock_server_send(client_sock, frame, frame_len);
    if (sent < (int)frame_len) {
        LOG_ERR("GW TCP send failed on sock %d: %d", client_sock, sent);
    }
}

/* Register scratch for the gateway forward. Lives at file scope (not on the
 * stack) because this handler runs only on the single modbus worker thread
 * (via modbus_gw_fwd_exec), one transaction at a time - so a shared static is
 * safe and keeps the worker's 2 KB stack within budget despite the 125-reg
 * (250 B) working set. Do NOT call modbus_gateway_handler from any other
 * thread without revisiting this. */
static uint16_t modbus_gw_regs[125];

static int modbus_gateway_handler(const struct modbus_adu *req,
                                  struct modbus_adu *resp,
                                  void *user_data)
{
    uint16_t addr = 0;
    uint16_t qty_or_val = 0;

    if (req->length >= 2) {
        addr = (req->data[0] << 8) | req->data[1];
    }
    if (req->length >= 4) {
        qty_or_val = (req->data[2] << 8) | req->data[3];
    }

    /*LOG_INF("GW req: unit=%u fc=0x%02X(%s) addr=%u qty/val=%u",
            req->unit_id, req->fc, modbus_fc_to_str(req->fc),
            addr, qty_or_val);
    */

    int client_idx = *(int *)user_data;

    if (client_idx < 0) {
        resp->unit_id = req->unit_id;
        resp->fc = req->fc | 0x80;
        resp->data[0] = 0x0A; /* Gateway Path Unavailable */
        resp->length = 1;
        return 0;
    }

    resp->unit_id = req->unit_id;
    resp->fc = req->fc;
    int err = 0;

    switch (req->fc) {
    case 0x01: { /* Read Coils */
        uint16_t count = qty_or_val;
        uint8_t byte_count = (count + 7) / 8;
        uint8_t coil_tbl[32] = {};
        err = modbus_client_read_coils(client_idx, req->unit_id,
                                       addr, coil_tbl, count);
        if (err == 0) {
            resp->data[0] = byte_count;
            memcpy(&resp->data[1], coil_tbl, byte_count);
            resp->length = 1 + byte_count;
        }
        break;
    }
    case 0x02: { /* Read Discrete Inputs */
        uint16_t count = qty_or_val;
        uint8_t byte_count = (count + 7) / 8;
        uint8_t di_tbl[32] = {};
        err = modbus_client_read_dinputs(client_idx, req->unit_id,
                                         addr, di_tbl, count);
        if (err == 0) {
            resp->data[0] = byte_count;
            memcpy(&resp->data[1], di_tbl, byte_count);
            resp->length = 1 + byte_count;
        }
        break;
    }
    case 0x03: { /* Read Holding Registers */
        uint16_t count = qty_or_val;
        uint16_t *regs = modbus_gw_regs;
        err = modbus_client_read_holding_regs(client_idx, req->unit_id,
                                              addr, regs, count);
        if (err == 0) {
            resp->data[0] = count * 2;
            for (uint16_t i = 0; i < count; i++) {
                resp->data[1 + i * 2] = regs[i] >> 8;
                resp->data[2 + i * 2] = regs[i] & 0xFF;
            }
            resp->length = 1 + count * 2;
        }
        break;
    }
    case 0x04: { /* Read Input Registers */
        uint16_t count = qty_or_val;
        uint16_t *regs = modbus_gw_regs;
        err = modbus_client_read_input_regs(client_idx, req->unit_id,
                                            addr, regs, count);
        if (err == 0) {
            resp->data[0] = count * 2;
            for (uint16_t i = 0; i < count; i++) {
                resp->data[1 + i * 2] = regs[i] >> 8;
                resp->data[2 + i * 2] = regs[i] & 0xFF;
            }
            resp->length = 1 + count * 2;
        }
        break;
    }
    case 0x05: { /* Write Single Coil */
        bool state = (qty_or_val == 0xFF00);
        err = modbus_client_write_coil(client_idx, req->unit_id,
                                       addr, state);
        if (err == 0) {
            memcpy(resp->data, req->data, req->length);
            resp->length = req->length;
        }
        break;
    }
    case 0x06: { /* Write Single Register */
        err = modbus_client_write_holding_reg(client_idx, req->unit_id,
                                              addr, qty_or_val);
        if (err == 0) {
            memcpy(resp->data, req->data, req->length);
            resp->length = req->length;
        }
        break;
    }
    case 0x10: { /* Write Multiple Registers */
        uint16_t count = qty_or_val;
        uint16_t *regs = modbus_gw_regs;
        /* Clear unparsed entries: the shared static isn't zero-initialized
         * per call, and a short/malformed body must not write stale values. */
        memset(regs, 0, sizeof(modbus_gw_regs));
        for (uint16_t i = 0; i < count && (5 + i * 2 + 1) < req->length; i++) {
            regs[i] = (req->data[5 + i * 2] << 8) | req->data[6 + i * 2];
        }
        err = modbus_client_write_holding_regs(client_idx, req->unit_id,
                                               addr, regs, count);
        if (err == 0) {
            memcpy(resp->data, req->data, 4);
            resp->length = 4;
        }
        break;
    }
    default:
        resp->fc = req->fc | 0x80;
        resp->data[0] = 0x01; /* Illegal Function */
        resp->length = 1;
        return 0;
    }

    if (err != 0) {
        LOG_WRN("GW forward failed: fc=0x%02X addr=%u err=%d",
                req->fc, addr, err);
        resp->fc = req->fc | 0x80;
        /* 0x0B = Gateway Target Device Failed to Respond (timeout)
         * 0x04 = Slave Device Failure (other errors) */
        resp->data[0] = (err == -ETIMEDOUT) ? 0x0B : 0x04;
        resp->length = 1;
    } else {
        /*LOG_INF("GW resp: unit=%u fc=0x%02X len=%u",
                resp->unit_id, resp->fc, resp->length);
        */
    }

    return 0;
}


/*
 * Gateway forward off-loading.
 *
 * The blocking RTU transaction must NOT run on the socket-server work queue
 * (low_priority_wq): an unresponsive slave makes each forward block for the
 * RTU timeout, and a burst of pipelined requests would stall that queue long
 * enough to starve its task-watchdog heartbeat and reboot the device
 * (BOOT_REBOOT_WATCHDOG_WQ_LOW). Instead each parsed request is copied into a
 * pool slot and handed to the existing modbus worker thread via
 * modbus_client_submit_work() - reusing the one thread that already serializes
 * the bus, rather than spawning another (saves the extra thread stack). The
 * recv callback only does cheap, non-blocking work (parse + copy + enqueue)
 * and returns immediately.
 *
 * The pool is the per-callback cap: at most MODBUS_GW_FWD_POOL forwards can be
 * outstanding (kept small to bound RAM - each slot holds a full ~264 B ADU).
 * When the pool or worker queue is saturated the gateway answers
 * Server-Device-Busy and the master retries, rather than the recv callback
 * blocking or queueing unboundedly.
 */
#define MODBUS_GW_FWD_POOL 8

struct modbus_gw_fwd {
    bool in_use;
    int client_sock;
    int client_idx;
    struct modbus_adu req;
};

static struct modbus_gw_fwd modbus_gw_fwd_pool[MODBUS_GW_FWD_POOL];
K_MUTEX_DEFINE(modbus_gw_fwd_lock);

static struct modbus_gw_fwd *modbus_gw_fwd_alloc(void)
{
    struct modbus_gw_fwd *slot = NULL;

    k_mutex_lock(&modbus_gw_fwd_lock, K_FOREVER);
    for (size_t i = 0; i < ARRAY_SIZE(modbus_gw_fwd_pool); i++) {
        if (!modbus_gw_fwd_pool[i].in_use) {
            modbus_gw_fwd_pool[i].in_use = true;
            slot = &modbus_gw_fwd_pool[i];
            break;
        }
    }
    k_mutex_unlock(&modbus_gw_fwd_lock);
    return slot;
}

static void modbus_gw_fwd_free(struct modbus_gw_fwd *f)
{
    k_mutex_lock(&modbus_gw_fwd_lock, K_FOREVER);
    f->in_use = false;
    k_mutex_unlock(&modbus_gw_fwd_lock);
}

/* Runs on the modbus worker thread (see modbus_client_submit_work). Performs
 * the blocking RTU transaction and sends the response on the originating TCP
 * socket, then releases the pool slot. Forwards are serialized through the one
 * worker, which matches the single shared RTU bus. The response ADU is static
 * (one forward at a time) to keep the worker's 2 KB stack within budget. */
static void modbus_gw_fwd_exec(void *arg)
{
    struct modbus_gw_fwd *f = (struct modbus_gw_fwd *)arg;
    static struct modbus_adu resp;

    memset(&resp, 0, sizeof(resp));
    resp.trans_id = f->req.trans_id;
    resp.proto_id = f->req.proto_id;

    int rc = modbus_gateway_handler(&f->req, &resp, &f->client_idx);
    if (rc == 0) {
        modbus_gw_send_resp(f->client_sock, &resp);
    } else {
        LOG_WRN("GW handler failed: %d", rc);
    }

    modbus_gw_fwd_free(f);
}

/* Send a Modbus exception for a request we could not forward (backpressure
 * when the worker pool/queue is saturated, or no RTU client configured). */
static void modbus_gw_send_exception(int client_sock,
                                     const struct modbus_adu *req,
                                     uint8_t exc)
{
    struct modbus_adu resp;

    memset(&resp, 0, sizeof(resp));
    resp.trans_id = req->trans_id;
    resp.proto_id = req->proto_id;
    resp.unit_id  = req->unit_id;
    resp.fc       = req->fc | 0x80;
    resp.data[0]  = exc;
    resp.length   = 1;
    modbus_gw_send_resp(client_sock, &resp);
}

