/* ------------------------------------------------------------------ */
/* Modbus TCP gateway proxying on the S1..S4 socket servers.
 *
 * MBAP frames arrive as a TCP byte stream via the sock_server recv
 * callbacks. Bytes accumulate per client socket until a full ADU is
 * assembled, then the request is forwarded to the RTU side through
 * modbus_gateway_handler and the response is sent back on the same
 * socket.
 */

struct modbus_gw_stream {
    int sock;       /* owning client socket, -1 = free */
    size_t pos;     /* bytes accumulated in buf */
    uint8_t buf[MODBUS_MBAP_AND_FC_LENGTH + sizeof(((struct modbus_adu *)0)->data)];
};

static struct modbus_gw_stream modbus_gw_streams[4 * SOCK_SERVER_MAX_CLIENTS];
static bool modbus_gw_streams_inited;

static struct modbus_gw_stream *modbus_gw_stream_get(int sock)
{
    struct modbus_gw_stream *free_slot = NULL;

    if (!modbus_gw_streams_inited) {
        for (size_t i = 0; i < ARRAY_SIZE(modbus_gw_streams); i++) {
            modbus_gw_streams[i].sock = -1;
        }
        modbus_gw_streams_inited = true;
    }

    for (size_t i = 0; i < ARRAY_SIZE(modbus_gw_streams); i++) {
        if (modbus_gw_streams[i].sock == sock) {
            return &modbus_gw_streams[i];
        }
        if (modbus_gw_streams[i].sock < 0 && free_slot == NULL) {
            free_slot = &modbus_gw_streams[i];
        }
    }

    if (free_slot) {
        free_slot->sock = sock;
        free_slot->pos = 0;
    }
    return free_slot;
}

static void modbus_gw_stream_release(int client_sock)
{
    for (size_t i = 0; i < ARRAY_SIZE(modbus_gw_streams); i++) {
        if (modbus_gw_streams[i].sock == client_sock) {
            modbus_gw_streams[i].sock = -1;
            modbus_gw_streams[i].pos = 0;
        }
    }
}

static void modbus_gw_sock_recv(int client_sock, const uint8_t *data,
                                size_t len, int *client_idx)
{
    struct modbus_gw_stream *st = modbus_gw_stream_get(client_sock);

    if (st == NULL) {
        LOG_ERR("GW: no stream slot for sock %d", client_sock);
        return;
    }

    while (len > 0) {
        size_t take = MIN(len, sizeof(st->buf) - st->pos);

        memcpy(st->buf + st->pos, data, take);
        st->pos += take;
        data += take;
        len -= take;

        /* Hand off every complete MBAP frame currently in the buffer to the
         * modbus worker thread. This loop never blocks: a saturated worker
         * just yields a Busy reply for that frame. */
        while (st->pos >= MODBUS_MBAP_AND_FC_LENGTH) {
            struct modbus_adu req;

            memset(&req, 0, sizeof(req));
            modbus_raw_get_header(&req, st->buf);
            if (req.length > sizeof(req.data)) {
                LOG_ERR("GW: oversized ADU length %u on sock %d",
                        req.length, client_sock);
                st->pos = 0;
                return;
            }

            size_t frame_len = MODBUS_MBAP_AND_FC_LENGTH + req.length;
            if (st->pos < frame_len) {
                break; /* wait for the rest of the body */
            }
            memcpy(req.data, st->buf + MODBUS_MBAP_AND_FC_LENGTH, req.length);

            int idx = *client_idx;
            struct modbus_gw_fwd *f = (idx >= 0) ? modbus_gw_fwd_alloc() : NULL;

            if (f != NULL) {
                f->client_sock = client_sock;
                f->client_idx  = idx;
                memcpy(&f->req, &req, sizeof(req));

                /* Non-blocking hand-off to the modbus worker thread. */
                if (modbus_client_submit_work(modbus_gw_fwd_exec, f) != 0) {
                    modbus_gw_fwd_free(f);
                    f = NULL;
                }
            }

            if (f == NULL) {
                /* No capacity to forward (pool/worker queue saturated) or no
                 * RTU client configured. Answer Server-Device-Busy (0x06) /
                 * Gateway-Path-Unavailable (0x0A) so the master retries; the
                 * frame is still consumed to keep the byte stream aligned. */
                modbus_gw_send_exception(client_sock, &req,
                                         (idx >= 0) ? 0x06 : 0x0A);
            }

            st->pos -= frame_len;
            memmove(st->buf, st->buf + frame_len, st->pos);
        }
    }
}

/* Modbus TCP gateway proxying on the S1..S4 socket servers */
static void modbus_gw_sock_recv(int client_sock, const uint8_t *data,
                                size_t len, int *client_idx);
static void modbus_gw_stream_release(int client_sock);
